// Construye la cache key a partir de lat/lon o address.
// Política de claves:
//   - Si lat+lon presentes: 'geo:<lat5>,<lon5>' (5 decimales ≈ 1.1 m de resolución).
//     Suficiente para distinguir techos vecinos sin fragmentar el cache por jitter
//     submétrico de pines de mapa.
//   - Else if address: 'addr:<lowercase-trim-collapse>' tras normalizar abreviaturas.
//   - Else: error de input.
//
// El Postgres node siguiente busca esta key. Si Postgres falla (ej: conexión),
// marcamos cacheError y dejamos pasar al Solar API directo (degradación).

const src = $input.first().json;
const body = src.body || src;
const address = (body.address || '').toString().trim();
const lat = body.lat != null ? Number(body.lat) : null;
const lon = body.lon != null ? Number(body.lon) : null;

if (!address && (lat == null || lon == null || Number.isNaN(lat) || Number.isNaN(lon))) {
  return [{ json: { ok: false, reason: 'invalid_input', detail: 'address o lat/lon requeridos' } }];
}

let cacheKey;
if (lat != null && lon != null && !Number.isNaN(lat) && !Number.isNaN(lon)) {
  cacheKey = 'geo:' + lat.toFixed(5) + ',' + lon.toFixed(5);
} else {
  // Normalización mínima del address para colisión consistente en el cache.
  const normalized = address
    .toLowerCase()
    .replace(/[áàä]/g, 'a').replace(/[éèë]/g, 'e').replace(/[íìï]/g, 'i')
    .replace(/[óòö]/g, 'o').replace(/[úùü]/g, 'u').replace(/ñ/g, 'n')
    .replace(/[.,#]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  cacheKey = 'addr:' + normalized;
}

return [{ json: { cacheKey, address, lat, lon, body } }];

// Decide HIT vs MISS. Tolerante a fallos del Postgres node (continueOnFail=true):
// si la consulta no devolvió nada o devolvió un error, tratamos como MISS y dejamos
// que el flujo descargue desde Google. Así el cache nunca degrada el servicio.

const meta = $('Build cache key').first().json;
const lookup = $input.all();
const row = (lookup && lookup.length > 0 && lookup[0].json && lookup[0].json.response) ? lookup[0].json : null;

if (row && row.response) {
  return [{ json: {
    cacheKey: meta.cacheKey,
    address: meta.address,
    lat: meta.lat,
    lon: meta.lon,
    body: meta.body,
    cacheHit: true,
    cacheAgeSec: row.created_at ? Math.floor((Date.now() - new Date(row.created_at).getTime()) / 1000) : null,
    cacheExpiresAt: row.expires_at || null,
    cacheHitCount: row.hit_count || 0,
    cachedResponse: row.response,
    cachedSource: row.source,
    cachedConfidence: row.confidence,
  }, pairedItem: { item: 0 } }];
}
return [{ json: {
  cacheKey: meta.cacheKey,
  address: meta.address,
  lat: meta.lat,
  lon: meta.lon,
  body: meta.body,
  cacheHit: false,
}, pairedItem: { item: 0 } }];

// Devuelve la respuesta cacheada con metadata de cache (cacheHit, cacheAgeSec).
// El frontend puede usar estos campos para mostrar 'datos guardados hace 12d'.
const meta = $('Hit or miss').first().json;
const body = meta.cachedResponse || {};
return [{ json: {
  ...body,
  cacheHit: true,
  cacheAgeSec: meta.cacheAgeSec,
  cacheExpiresAt: meta.cacheExpiresAt,
  cacheHitCount: (meta.cacheHitCount || 0) + 1,
} }];

// Prepara INSERT a solar_cache solo si la respuesta es válida (ok != false).
// Pasa al siguiente nodo dos campos: la respuesta (para devolver) y un flag
// shouldCache que el Postgres node usa para decidir si insertar.
//
// Respuestas con ok:false (geocode_no_results, missing_env, etc.) NO se cachean —
// queremos que se reintenten en la siguiente request por si el problema fue
// transitorio o el usuario corrige el input.

const meta = $('Hit or miss').first().json;
const response = $input.first().json;
const isValid = response && typeof response === 'object' && response.ok !== false;

return [{ json: {
  cacheKey: meta.cacheKey,
  address: meta.address,
  lat: meta.lat,
  lon: meta.lon,
  response,
  source: response?.source || null,
  confidence: response?.confidence != null ? Number(response.confidence) : null,
  shouldCache: isValid,
} }];

// Devuelve la respuesta fresca de solar-roof con metadata cacheHit:false.
// Si la respuesta era inválida (ok:false), se propaga sin alterar — el frontend
// ya sabe manejarla.
const prep = $('Prepare cache insert').first().json;
const body = prep.response || {};
return [{ json: {
  ...body,
  cacheHit: false,
  cacheStored: prep.shouldCache === true,
} }];
